    """Test when no path exists between source and destination."""
    graph = {
        'A': [('B', 1.0)],
        'B': [('C', 2.0)],
        'C': [],
        'D': [('E', 1.0)],
        'E': []
    }

    distance, path = shortest_path(graph, 'A', 'E')
