from typing import Dict, List, Tuple

def shortest_path(graph: Dict[str, List[Tuple[str, int]]], start: str, end: str) -> Tuple[float, List[str]]:
    """
    Find the shortest path between two nodes in a weighted graph.

    Args:
        graph: Dictionary mapping nodes to list of (neighbor, weight) tuples
        start: Starting node
        end: Destination node

    Returns:
        Tuple of (distance, path) where distance is the shortest distance 
        and path is the list of nodes in the shortest path
    """
    # Handle special case: start equals end
    if start == end:
        return (0.0, [start])

    # Initialize distances and previous nodes
    distances = {node: float('inf') for node in graph}

    # Handle case where start node doesn't exist in graph
    if start not in distances:
        return (float('inf'), [])

    distances[start] = 0
    previous = {}
    visited = set()

    # Priority queue: (distance, node)
    pq = [(0, start)]

    while pq:
        current_dist, current_node = heapq.heappop(pq)

        # Skip if already visited
        if current_node in visited:
            continue

        visited.add(current_node)

        # Check neighbors
        for neighbor, weight in graph.get(current_node, []):
            if neighbor not in visited:
                new_dist = current_dist + weight

                # If we found a shorter path, update it
                if new_dist < distances[neighbor]:
                    distances[neighbor] = new_dist
                    previous[neighbor] = current_node
                    heapq.heappush(pq, (new_dist, neighbor))

    # If end is unreachable or doesn't exist in graph
    if end not in distances or distances[end] == float('inf'):
        return (float('inf'), [])

    # Reconstruct path
    path = []
    current = end
    while current in previous:
        path.append(current)
        current = previous[current]
    path.append(start)
    path.reverse()

    return (distances[end], path)"}

